using System;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests
{
    public static class TestHelpers
    {
        public static SchoolContext CreateInMemoryContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateSeededContext()
        {
            var context = CreateInMemoryContext();
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var instructor1 = new Instructor
            {
                ID = 1,
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = new DateTime(2010, 3, 15)
            };
            var instructor2 = new Instructor
            {
                ID = 2,
                LastName = "Jones",
                FirstMidName = "Jane",
                HireDate = new DateTime(2012, 7, 20)
            };

            context.Instructors.AddRange(instructor1, instructor2);

            var department1 = new Department
            {
                DepartmentID = 1,
                Name = "Computer Science",
                Budget = 100000m,
                StartDate = new DateTime(2000, 9, 1),
                InstructorID = 1
            };
            var department2 = new Department
            {
                DepartmentID = 2,
                Name = "Mathematics",
                Budget = 75000m,
                StartDate = new DateTime(2005, 9, 1),
                InstructorID = 2
            };

            context.Departments.AddRange(department1, department2);

            var course1 = new Course
            {
                CourseID = 1001,
                Title = "Introduction to CS",
                Credits = 3,
                DepartmentID = 1
            };
            var course2 = new Course
            {
                CourseID = 1002,
                Title = "Data Structures",
                Credits = 4,
                DepartmentID = 1
            };
            var course3 = new Course
            {
                CourseID = 2001,
                Title = "Calculus I",
                Credits = 4,
                DepartmentID = 2
            };

            context.Courses.AddRange(course1, course2, course3);

            var student1 = new Student
            {
                ID = 10,
                LastName = "Doe",
                FirstMidName = "Alice",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };
            var student2 = new Student
            {
                ID = 11,
                LastName = "Brown",
                FirstMidName = "Bob",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };
            var student3 = new Student
            {
                ID = 12,
                LastName = "Wilson",
                FirstMidName = "Charlie",
                EnrollmentDate = new DateTime(2024, 1, 15)
            };

            context.Students.AddRange(student1, student2, student3);

            context.Enrollments.AddRange(
                new Enrollment { EnrollmentID = 1, CourseID = 1001, StudentID = 10, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, CourseID = 1002, StudentID = 10, Grade = Grade.B },
                new Enrollment { EnrollmentID = 3, CourseID = 2001, StudentID = 11, Grade = Grade.C }
            );

            context.CourseAssignments.AddRange(
                new CourseAssignment { CourseID = 1001, InstructorID = 1 },
                new CourseAssignment { CourseID = 1002, InstructorID = 1 },
                new CourseAssignment { CourseID = 2001, InstructorID = 2 }
            );

            context.SaveChanges();
        }
    }
}

using System;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new StudentsController(_context);
            // Setup TempData for controller
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(), new SessionStateTempDataProvider()); 
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedList()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Brown", model[0].LastName);
            Assert.Equal("Doe", model[1].LastName);
            Assert.Equal("Wilson", model[2].LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Wilson", model[0].LastName);
            Assert.Equal("Doe", model[1].LastName);
            Assert.Equal("Brown", model[2].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            // student1 and student2 have same date (2023-09-01), student3 is 2024-01-15
            Assert.Equal(new DateTime(2024, 1, 15), model.Last().EnrollmentDate);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(new DateTime(2024, 1, 15), model[0].EnrollmentDate);
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Doe", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Doe", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alice", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alice", model[0].FirstMidName);
        }

        [Fact]
        public void Index_SearchString_ResetsPageToOne()
        {
            var result = _controller.Index(null, null, "Doe", 3) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Doe", null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            _controller.Index("Date", null, "test", null);

            Assert.Equal("Date", _controller.ViewBag.CurrentSort);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
            Assert.Equal("test", _controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_EmptySortOrder_SetsNameSortParmToDesc()
        {
            _controller.Index(null, null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsStudentWithEnrollments()
        {
            var result = _controller.Details(10) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Doe", student.LastName);
            Assert.Equal(2, student.Enrollments.Count);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "New",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2024, 9, 1)
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_ValidStudent_AddsToDatabase()
        {
            var student = new Student
            {
                LastName = "New",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2024, 9, 1)
            };

            _controller.Create(student);

            Assert.Equal(4, _context.Students.Count());
        }

        [Fact]
        public void Create_Post_MinValueDate_AddsModelError()
        {
            var student = new Student
            {
                LastName = "New",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_DateOutOfRange_AddsModelError()
        {
            var student = new Student
            {
                LastName = "New",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                EnrollmentDate = new DateTime(2024, 9, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(student, result.Model);
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsStudentView()
        {
            var result = _controller.Edit(10) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Doe", student.LastName);
        }

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                ID = 10,
                LastName = "UpdatedDoe",
                FirstMidName = "Alice",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_MinValueDate_AddsModelError()
        {
            var student = new Student
            {
                ID = 10,
                LastName = "Doe",
                FirstMidName = "Alice",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 10,
                EnrollmentDate = new DateTime(2024, 1, 1)
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Delete Tests

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsStudentView()
        {
            var result = _controller.Delete(10) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Doe", student.LastName);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
        {
            var result = _controller.DeleteConfirmed(10) as RedirectToActionResult;

