using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover messages from other tests (shared static queue)
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_CreateOperation_EnqueuesMessage()
        {
            _service.SendNotification("Student", "1", "Alice Doe", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("Alice Doe", notification.Message);
            Assert.Contains("created", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Calculus", EntityOperation.UPDATE, "Teacher");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("updated", notification.Message);
            Assert.Contains("Calculus", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Department", "5", "Physics", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("deleted", notification.Message);
            Assert.Contains("Physics", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();

            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_FIFO_Order()
        {
            _service.SendNotification("A", "1", "First", EntityOperation.CREATE);
            _service.SendNotification("B", "2", "Second", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
        }

        [Fact]
        public void SendNotification_MultipleMessages_AllRetrievable()
        {
            for (int i = 0; i < 5; i++)
            {
                _service.SendNotification("Test", i.ToString(), $"Item{i}", EntityOperation.CREATE);
            }

            int count = 0;
            while (_service.ReceiveNotification() != null)
            {
                count++;
            }

            Assert.Equal(5, count);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(999));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName_Works()
        {
            _service.SendNotification("Instructor", "7", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Instructor", notification.EntityType);
            Assert.Equal("7", notification.EntityId);
            Assert.Contains("updated", notification.Message);
        }
    }
}

using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(5, result.Count);
            Assert.Equal(1, result[0]);
            Assert.Equal(5, result[4]);
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(5, result.Count);
            Assert.Equal(6, result[0]);
            Assert.Equal(10, result[4]);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(2, result.Count);
            Assert.Equal(11, result[0]);
            Assert.Equal(12, result[1]);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(3, result.TotalPages);
        }

        [Fact]
        public void TotalPages_ExactDivision()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(2, result.TotalPages);
        }

        [Fact]
        public void PageIndex_SetCorrectly()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(3, result.PageIndex);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 4, 5);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
        }

        [Fact]
        public void Create_SingleItem_ReturnsOneItem()
        {
            var source = new[] { 42 }.AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Single(result);
            Assert.Equal(42, result[0]);
            Assert.Equal(1, result.TotalPages);
        }

        [Fact]
        public void Constructor_SetsPropertiesCorrectly()
        {
            var items = new List<string> { "a", "b", "c" };

            var paginatedList = new PaginatedList<string>(items, 10, 2, 3);

            Assert.Equal(3, paginatedList.Count);
            Assert.Equal(2, paginatedList.PageIndex);
            Assert.Equal(4, paginatedList.TotalPages); // ceil(10/3) = 4
        }
    }
}

