using System;
using System.IO;
using System.Linq;
using System.Net;
using System.Text;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempPath;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _tempPath = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempPath);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempPath);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempPath);

            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(), new SessionStateTempDataProvider());
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempPath))
            {
                Directory.Delete(_tempPath, true);
            }
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithAllCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var courses = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);
            Assert.Equal(3, courses.Count);
        }

        [Fact]
        public void Index_IncludesDepartmentData()
        {
            var result = _controller.Index() as ViewResult;

            var courses = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);
            Assert.All(courses, c => Assert.NotNull(c.Department));
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsCourseWithDepartment()
        {
            var result = _controller.Details(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Introduction to CS", course.Title);
            Assert.NotNull(course.Department);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentList()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 3001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_ValidCourse_SavesInDatabase()
        {
            var course = new Course
            {
                CourseID = 3001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            _controller.Create(course, null);

            Assert.Equal(4, _context.Courses.Count());
            Assert.NotNull(_context.Courses.Find(3001));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 3001, DepartmentID = 1 };

            var result = _controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_WithValidImage_SavesFile()
        {
            var course = new Course
            {
                CourseID = 3001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.jpg", "image/jpeg", 1024);

            var result = _controller.Create(course, mockFile.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var savedCourse = _context.Courses.Find(3001);
            Assert.NotNull(savedCourse.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_WithInvalidExtension_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 3001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.exe", "application/octet-stream", 1024);

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_WithOversizedFile_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 3001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.jpg", "image/jpeg", 6 * 1024 * 1024);

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsCourseView()
        {
            var result = _controller.Edit(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Introduction to CS", course.Title);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Updated Course",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _controller.Edit(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1001, DepartmentID = 1 };

            var result = _controller.Edit(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Post_WithValidImage_UpdatesImagePath()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Updated Course",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("updated.png", "image/png", 2048);

            var result = _controller.Edit(course, mockFile.Object) as RedirectToActionResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_WithInvalidExtension_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Updated Course",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("bad.txt", "text/plain", 1024);

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Delete Tests

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsCourseView()
        {
            var result = _controller.Delete(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Introduction to CS", course.Title);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1001) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Courses.Find(1001));
        }

        #endregion

        #region Helpers

        private static Mock<IFormFile> CreateMockFormFile(string fileName, string contentType, long length)
        {
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.ContentType).Returns(contentType);
            mock.Setup(f => f.Length).Returns(length);
            var content = new byte[Math.Min(length, 1024)];
            var stream = new MemoryStream(content);
            mock.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => stream.CopyTo(s));
            mock.Setup(f => f.OpenReadStream()).Returns(stream);
            return mock;
        }

        #endregion
    }
}

