using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        #region Person / Student / Instructor Tests

        [Fact]
        public void Person_FullName_ReturnsConcatenation()
        {
            var student = new Student { LastName = "Smith", FirstMidName = "John" };

            Assert.Equal("Smith, John", student.FullName);
        }

        [Fact]
        public void Student_EnrollmentDate_Required()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2024, 1, 1)
            };

            var results = ValidateModel(student);
            Assert.Empty(results);
        }

        [Fact]
        public void Student_LastName_MaxLength50()
        {
            var student = new Student
            {
                LastName = new string('A', 51),
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2024, 1, 1)
            };

            var results = ValidateModel(student);
            Assert.Contains(results, v => v.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_FirstMidName_MaxLength50()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = new string('B', 51),
                EnrollmentDate = new DateTime(2024, 1, 1)
            };

            var results = ValidateModel(student);
            Assert.Contains(results, v => v.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Student_LastName_Required()
        {
            var student = new Student
            {
                LastName = null,
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2024, 1, 1)
            };

            var results = ValidateModel(student);
            Assert.Contains(results, v => v.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_FirstMidName_Required()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = null,
                EnrollmentDate = new DateTime(2024, 1, 1)
            };

            var results = ValidateModel(student);
            Assert.Contains(results, v => v.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Instructor_HireDate_Required()
        {
            var instructor = new Instructor
            {
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = new DateTime(2020, 1, 1)
            };

            var results = ValidateModel(instructor);
            Assert.Empty(results);
        }

        [Fact]
        public void Instructor_FullName_WorksCorrectly()
        {
            var instructor = new Instructor { LastName = "Jones", FirstMidName = "Jane" };

            Assert.Equal("Jones, Jane", instructor.FullName);
        }

        #endregion

        #region Course Tests

        [Fact]
        public void Course_Title_MinLength3()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "AB",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, v => v.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_Title_MaxLength50()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = new string('X', 51),
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, v => v.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_Credits_Range0To5()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Valid Title",
                Credits = 6,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, v => v.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_Credits_NegativeInvalid()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Valid Title",
                Credits = -1,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, v => v.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_Valid_NoErrors()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Valid Title",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Empty(results);
        }

        #endregion

        #region Department Tests

        [Fact]
        public void Department_Name_MinLength3()
        {
            var dept = new Department
            {
                Name = "AB",
                Budget = 1000m,
                StartDate = DateTime.Now
            };

            var results = ValidateModel(dept);
            Assert.Contains(results, v => v.MemberNames.Contains("Name"));
        }

        [Fact]
        public void Department_Name_MaxLength50()
        {
            var dept = new Department
            {
                Name = new string('X', 51),
                Budget = 1000m,
                StartDate = DateTime.Now
            };

            var results = ValidateModel(dept);
            Assert.Contains(results, v => v.MemberNames.Contains("Name"));
        }

        [Fact]
        public void Department_Valid_NoErrors()
        {
            var dept = new Department
            {
                Name = "Valid Department",
                Budget = 50000m,
                StartDate = DateTime.Now
            };

            var results = ValidateModel(dept);
            Assert.Empty(results);
        }

        #endregion

        #region Notification Tests

        [Fact]
        public void Notification_Properties_SetCorrectly()
        {
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "Test message",
                CreatedAt = DateTime.Now,
                CreatedBy = "Admin",
                IsRead = false
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("Test message", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        #endregion

        #region Enrollment Tests

        [Fact]
        public void Enrollment_GradeIsNullable()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 100,
                StudentID = 10,
                Grade = null
            };

            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Grade_HasCorrectValues()
        {
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(1, (int)Grade.B);
            Assert.Equal(2, (int)Grade.C);
            Assert.Equal(3, (int)Grade.D);
            Assert.Equal(4, (int)Grade.F);
        }

        #endregion

        #region OfficeAssignment Tests

        [Fact]
        public void OfficeAssignment_Location_MaxLength50()
        {
            var assignment = new OfficeAssignment
            {
                InstructorID = 1,
                Location = new string('X', 51)
            };

            var results = ValidateModel(assignment);
            Assert.Contains(results, v => v.MemberNames.Contains("Location"));
        }

        [Fact]
        public void OfficeAssignment_Valid_NoErrors()
        {
            var assignment = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Room 101"
            };

            var results = ValidateModel(assignment);
            Assert.Empty(results);
        }

        #endregion

        #region CourseAssignment Tests

        [Fact]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            var assignment = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 100
            };

            Assert.Equal(1, assignment.InstructorID);
            Assert.Equal(100, assignment.CourseID);
        }

        #endregion

        #region SchoolViewModels Tests

        [Fact]
        public void InstructorIndexData_PropertiesAreSettable()
        {
            var data = new ContosoUniversity.Models.SchoolViewModels.InstructorIndexData
            {
                Instructors = new List<Instructor>(),
                Courses = new List<Course>(),
                Enrollments = new List<Enrollment>()
            };

            Assert.NotNull(data.Instructors);
            Assert.NotNull(data.Courses);
            Assert.NotNull(data.Enrollments);
        }

        [Fact]
        public void AssignedCourseData_PropertiesAreSettable()
        {
            var data = new ContosoUniversity.Models.SchoolViewModels.AssignedCourseData
            {
                CourseID = 100,
                Title = "Test Course",
                Assigned = true
            };

            Assert.Equal(100, data.CourseID);
            Assert.Equal("Test Course", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void EnrollmentDateGroup_PropertiesAreSettable()
        {
            var group = new ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup
            {
                EnrollmentDate = new DateTime(2024, 1, 1),
                StudentCount = 5
            };

            Assert.Equal(new DateTime(2024, 1, 1), group.EnrollmentDate);
            Assert.Equal(5, group.StudentCount);
        }

        #endregion

        #region Helpers

        private static IList<ValidationResult> ValidateModel(object model)
        {
            var context = new ValidationContext(model, null, null);
            var results = new List<ValidationResult>();
            Validator.TryValidateObject(model, context, results, true);
            return results;
        }

        #endregion
    }
}

